@import "tailwindcss";
@import "tw-animate-css";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --font-sans: var(--font-dm-sans);
  --color-sidebar-ring: var(--sidebar-ring);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar: var(--sidebar);
  --color-chart-5: var(--chart-5);
  --color-chart-4: var(--chart-4);
  --color-chart-3: var(--chart-3);
  --color-chart-2: var(--chart-2);
  --color-chart-1: var(--chart-1);
  --color-ring: var(--ring);
  --color-input: var(--input);
  --color-border: var(--border);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-accent-foreground: var(--accent-foreground);
  --color-accent: var(--accent);
  --color-muted-foreground: var(--muted-foreground);
  --color-muted: var(--muted);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-secondary: var(--secondary);
  --color-primary-foreground: var(--primary-foreground);
  --color-primary: var(--primary);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
  --radius-2xl: calc(var(--radius) + 8px);
  --radius-3xl: calc(var(--radius) + 12px);
  --radius-4xl: calc(var(--radius) + 16px);
  /* Semantic status colors */
  --color-success: var(--success);
  --color-success-bg: var(--success-bg);
  --color-success-foreground: var(--success-foreground);
  --color-warning: var(--warning);
  --color-warning-bg: var(--warning-bg);
  --color-warning-foreground: var(--warning-foreground);
  --color-error: var(--error);
  --color-error-bg: var(--error-bg);
  --color-error-foreground: var(--error-foreground);
  --color-info: var(--info);
  --color-info-bg: var(--info-bg);
  --color-info-foreground: var(--info-foreground);
  --color-star: var(--star);
}

:root {
  --radius: 0.625rem;
  /* Core palette from design-system.pen (hex -> oklch) */
  --background: oklch(1 0 0);                     /* #FFFFFF */
  --foreground: oklch(0.156 0 0);                  /* #1A1A1A */
  --card: oklch(0.985 0.002 247.839);              /* #F9FAFB */
  --card-foreground: oklch(0.156 0 0);             /* #1A1A1A */
  --popover: oklch(1 0 0);                         /* #FFFFFF */
  --popover-foreground: oklch(0.156 0 0);          /* #1A1A1A */
  --primary: oklch(0.546 0.245 262.881);           /* #2563EB */
  --primary-foreground: oklch(1 0 0);              /* #FFFFFF */
  --secondary: oklch(0.967 0.003 264.542);         /* #F3F4F6 */
  --secondary-foreground: oklch(0.372 0.044 257.287); /* #374151 */
  --muted: oklch(0.967 0.003 264.542);             /* #F3F4F6 */
  --muted-foreground: oklch(0.554 0.046 257.417);  /* #6B7280 */
  --accent: oklch(0.97 0.014 254.604);             /* #EFF6FF */
  --accent-foreground: oklch(0.546 0.245 262.881); /* #2563EB */
  --destructive: oklch(0.577 0.245 27.325);        /* #EF4444 */
  --destructive-foreground: oklch(1 0 0);          /* #FFFFFF */
  --border: oklch(0.928 0.006 264.531);            /* #E5E7EB */
  --input: oklch(0.928 0.006 264.531);             /* #E5E7EB */
  --ring: oklch(0.546 0.245 262.881);              /* #2563EB (matches primary) */
  /* Chart colors */
  --chart-1: oklch(0.646 0.222 41.116);
  --chart-2: oklch(0.6 0.118 184.704);
  --chart-3: oklch(0.398 0.07 227.392);
  --chart-4: oklch(0.828 0.189 84.429);
  --chart-5: oklch(0.769 0.188 70.08);
  /* Sidebar (storefront defaults - light) */
  --sidebar: oklch(1 0 0);
  --sidebar-foreground: oklch(0.156 0 0);
  --sidebar-primary: oklch(0.546 0.245 262.881);
  --sidebar-primary-foreground: oklch(1 0 0);
  --sidebar-accent: oklch(0.967 0.003 264.542);
  --sidebar-accent-foreground: oklch(0.156 0 0);
  --sidebar-border: oklch(0.928 0.006 264.531);
  --sidebar-ring: oklch(0.546 0.245 262.881);
  /* Semantic status */
  --success: oklch(0.723 0.219 149.579);           /* #22C55E */
  --success-bg: oklch(0.982 0.018 155.826);        /* #F0FDF4 */
  --success-foreground: oklch(0.393 0.095 152.535); /* #166534 */
  --warning: oklch(0.769 0.188 70.08);             /* #F59E0B */
  --warning-bg: oklch(0.987 0.022 95.277);         /* #FFFBEB */
  --warning-foreground: oklch(0.473 0.137 46.201); /* #92400E */
  --error: oklch(0.577 0.245 27.325);              /* #EF4444 */
  --error-bg: oklch(0.971 0.013 17.38);            /* #FEF2F2 */
  --error-foreground: oklch(0.396 0.141 25.723);   /* #991B1B */
  --info: oklch(0.588 0.213 259.815);              /* #3B82F6 */
  --info-bg: oklch(0.97 0.014 254.604);            /* #EFF6FF */
  --info-foreground: oklch(0.392 0.136 265.755);   /* #1E40AF */
  --star: oklch(0.828 0.189 84.429);               /* #FBBF24 */
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
}

import type { Metadata } from "next";
import { DM_Sans } from "next/font/google";
import "./globals.css";
import { SessionProvider } from "@/components/providers/session-provider";

const dmSans = DM_Sans({
  subsets: ["latin"],
  weight: ["400", "500", "600"],
  variable: "--font-dm-sans",
  display: "swap",
});

export const metadata: Metadata = {
  title: "MicroCommerce",
  description: "Premium electronics store",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" className={`${dmSans.variable} antialiased`}>
      <body>
        <SessionProvider>{children}</SessionProvider>
      </body>
    </html>
  );
}

